-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_refund_amount_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    channel,
    SUM(order_value_minor) AS gross_revenue_minor,
    SUM(net_revenue_minor) AS net_revenue_minor
  FROM iceberg.brain_serving.semantic_order
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  currency_code,
  channel,
  gross_revenue_minor,
  net_revenue_minor,
  (gross_revenue_minor - net_revenue_minor) AS refund_amount
FROM base;
